CREATE TABLE IF NOT EXISTS province_boundaries (
  id          SERIAL PRIMARY KEY,
  prov_nam_t  TEXT,
  prov_nam_e  TEXT,
  prov_code   TEXT,
  p_code      TEXT,
  region      TEXT,
  geom        GEOMETRY(MultiPolygon, 4326)
);

CREATE INDEX IF NOT EXISTS idx_province_boundaries_geom
  ON province_boundaries USING GIST(geom);
CREATE INDEX IF NOT EXISTS idx_province_boundaries_prov_nam_t
  ON province_boundaries (prov_nam_t);
CREATE INDEX IF NOT EXISTS idx_province_boundaries_prov_code
  ON province_boundaries (prov_code);

-- Drop legacy table if it exists (renamed to province_boundaries)
DROP TABLE IF EXISTS rayong_boundary;

